sql:
SELECT website_name
FROM websites
WHERE author_attributions = (SELECT MAX(author_attributions) FROM websites);

SELECT MAX(clicks) AS max_clicks
FROM url_tracking
WHERE website_id = 1;

SELECT content_type, SUM(views) AS total_views
FROM author_attributions
GROUP BY content_type;

SELECT SUM(clicks) AS total_clicks
FROM url_tracking
WHERE website_id = 1;

SELECT clicks, conversion_rate
FROM url_tracking
WHERE url = 'store.taylorswift.com/';

SELECT COUNT(*) 
FROM author_attributions
WHERE attribution_date >= '2023-01-01' AND attribution_date <= '2023-06-30';

SELECT page_url, bounce_rate, engagement_score
FROM webpage_metrics
WHERE engagement_score > 0.5;

SELECT COUNT(*) AS planned_content_updates
FROM content_calendar
WHERE website_id = 1 AND status = 'planned';

external_knowledge:
Top authors are defined as those having the highest attribution counts on a given website; 
The attribution count is a measure of how many times an author is attributed on a website; 
Total views represent the total number of views for all content attributed to an author on a website.

